function DefaultCurrency9232() {}
DefaultCurrency9232.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9232.tabIndex = -1;
DefaultCurrency9232.maxLength = 1;
DefaultCurrency9232.isReadOnly = function(){return true;}
DefaultCurrency9232.isTemporary = function(){return true;}
DefaultCurrency9232.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
